#include <stdio.h>
#include <stdlib.h>

// Structure for an adjacency list node
typedef struct AdjListNode {
    int val;
    struct AdjListNode* next;
} AdjListNode;

// Structure for a graph
typedef struct Graph {
    int V;
    AdjListNode** adjLists;
} Graph;

// Function to create a new adjacency list node
AdjListNode* createNode(int val) {
    AdjListNode* newNode = (AdjListNode*) malloc(sizeof(AdjListNode));
    if (!newNode) {
        printf("Memory error
");
        return NULL;
    }
    newNode->val = val;
    newNode->next = NULL;
    return newNode;
}

// Function to create a graph with V vertices
Graph* createGraph(int V) {
    Graph* graph = (Graph*) malloc(sizeof(Graph));
    if (!graph) {
        printf("Memory error
");
        return NULL;
    }
    graph->V = V;
    graph->adjLists = (AdjListNode**) malloc(V * sizeof(AdjListNode*));
    for (int i = 0; i < V; i++) {
        graph->adjLists[i] = NULL;
    }
    return graph;
}

// Function to add an edge to the graph
void addEdge(Graph* graph, int src, int dest) {
    AdjListNode* newNode = createNode(dest);
    newNode->next = graph->adjLists[src];
    graph->adjLists[src] = newNode;
}

// Function to perform DFS traversal
void dfs(Graph* graph, int v, int* visited, int* result, int* index) {
    visited[v] = 1;
    result[(*index)++] = v;
    AdjListNode* temp = graph->adjLists[v];
    while (temp) {
        if (!visited[temp->val]) {
            dfs(graph, temp->val, visited, result, index);
        }
        temp = temp->next;
    }
}

int main() {
    int V = 5;
    Graph* graph = createGraph(V);
    addEdge(graph, 0, 1);
    addEdge(graph, 0, 2);
    addEdge(graph, 1, 3);
    addEdge(graph, 1, 4);
    addEdge(graph, 2, 5);
    addEdge(graph, 3, 6);
    addEdge(graph, 4, 7);
    addEdge(graph, 5, 8);
    addEdge(graph, 6, 9);
    int* visited = (int*) malloc(V * sizeof(int));
    int* result = (int*) malloc(V * sizeof(int));
    int index = 0;
    for (int i = 0; i < V; i++) {
        visited[i] = 0;
    }
    dfs(graph, 0, visited, result, &index);
    for (int i = 0; i < V; i++) {
        printf("%d ", result[i]);
    }
    printf("\n");
    return 0;
}

